	t.Run("returns taskstore.db under .kasmos in working directory", func(t *testing.T) {
		projectDir := t.TempDir()
		t.Chdir(projectDir)

		dbPath := ResolvedDBPath()

		assert.Equal(t, filepath.Join(projectDir, ".kasmos", "taskstore.db"), dbPath)
	})
